import { mkdirSync, readFileSync, writeFileSync } from 'node:fs'
import { dirname, resolve } from 'node:path'
import { fileURLToPath } from 'node:url'

const scriptDir = dirname(fileURLToPath(import.meta.url))
const rootDir = resolve(scriptDir, '..')
const assetDir = resolve(rootDir, 'assets')
const outputDir = resolve(rootDir, 'src/generated')
const outputFile = resolve(outputDir, 'script-assets.ts')

const files = [
  ['agent-install.sh', 'AGENT_INSTALL_SCRIPT_TEMPLATE'],
  ['release-apply.sh', 'RELEASE_APPLY_SCRIPT_TEMPLATE'],
]

const lines = [
  '// Generated by scripts/generate-script-assets.mjs from apps/api/assets/*.sh.',
  '// Do not edit this file directly.',
  '',
]

for (const [fileName, exportName] of files) {
  const content = readFileSync(resolve(assetDir, fileName), 'utf8').replace(/\r\n?/g, '\n')
  lines.push(`export const ${exportName} = ${JSON.stringify(content)}`)
  lines.push('')
}

mkdirSync(outputDir, { recursive: true })
writeFileSync(outputFile, `${lines.join('\n')}\n`, 'utf8')
